var e=JSON.parse(`[{"id":"L15_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"키하! 캬하하하하하하하하하하────────!","JPN":"キャハ！　キャハハハハハハハハハ────────！","ENG":"Kihah! Kyahahahahahahahahahaha────────!","TWN":"呀哈！咔哈哈哈哈哈哈哈哈哈哈────────！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"이거 끝내주는데! 역시 자유로운 육체가 있다는 건 행복한 일이이구만──!","JPN":"すげぇじゃねぇか！　やっぱり自由な身体があるって幸せだなあ──！","ENG":"This is incredible! Having a free body of my own really is bliss──!","TWN":"這真是超爽的耶！果然擁有自由的肉體就是幸福啊──！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그런 건가…….","JPN":"そうか……","ENG":"Is that so...","TWN":"原來如此……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"베는 동작과 실제 참격 사이에 간극이 있군.","JPN":"斬る動作と実際の斬撃の間に隙がある。","ENG":"There's a gap between the swing and the actual slash.","TWN":"揮砍動作與實際斬擊之間有時間差。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"기습에 특화된 능력. 네놈의 검은 한치 앞의 미래를 베는 건가?","JPN":"奇襲に特化した能力。貴様の剣は一足先の未来を斬るのか？","ENG":"An ability specialized for ambushes. Does your blade cut the immediate future itself?","TWN":"專精於偷襲的能力。你的劍，是要斬斷眼前的未來嗎？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"오, 한 눈에 알아봤다고?","JPN":"お、一目でわかったのか？","ENG":"Oh? You figured it out at a glance?","TWN":"喔，一眼就被你看穿了？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 어쩔 건데? 네가 뭘 할 수 있지?","JPN":"それで？　お前に何ができる？","ENG":"So what now? What can you even do?","TWN":"那又怎樣？你能做什麼？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"신성을 각성하여, 제법 특이한 능력을 발현한 모양이지만…….","JPN":"神聖を覚醒し、かなり特殊な能力が発現したようだが……","ENG":"It seems you've awakened Divinity and manifested a rather unusual ability, but...","TWN":"看來你覺醒神性，發現了相當特殊的能力……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"아직은 허술하군.","JPN":"まだ隙だらけだ。","ENG":"You're still sloppy.","TWN":"不過，還不專精。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"꾸엑……!?","JPN":"くえっ……！？","ENG":"Agh...?!","TWN":"咕噁……！？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈을 여기서 살려 두면, 틀림없이 어머니의 적수가 되겠지.","JPN":"貴様をここで生かしておけば、間違いなくお母さんの敵になるだろう。","ENG":"If I leave you alive here, you'll surely become Mother's equal someday.","TWN":"如果讓你活著離開這裡，絕對會成為母親的勁敵。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"큭큭. 뭐야, 누님?","JPN":"くくっ、何だよ、姉さん。","ENG":"Keke. What is it, Sis?","TWN":"嘿嘿，怎麼了，姐姐？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"벌써 이만한 아들도 있어…? 오호, 재미 좀 봤나 본데……?","JPN":"もうこんなに大きい息子がいるのか……？　へえ、結構遊んだんだな……？","ENG":"You've already got a kid this big...? Oho, looks like you've had some fun, huh...?","TWN":"已經有這麼大的兒子了啊？哦～看來過得挺滋潤的嘛……？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"쓸데없는 소리로군. 이대로 질식해 죽어라……!","JPN":"無駄口を。このまま窒息して死ね……！","ENG":"Useless chatter. Suffocate and die right here...!","TWN":"無聊的胡言亂語。你就這樣窒息而死吧……！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"으갸아아아아악!! 야, 살려줘! 빨리 살려달라고오오오오!! 버네에엣……!!","JPN":"ぎゃああああっ！！　おい、助けてくれ！　早く助けてくれよおおお！！　バーネット……！！","ENG":"Gyaaaaaaah!! Hey, save me! Hurry, save me already!! Burneeetttttt...!!","TWN":"嗚啊啊啊啊啊啊！！喂，救命啊！快救我啦啊啊啊啊！！伯內特……！！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"이러다 리온 죽는다!? 진짜로 리온 죽는다아아아아……!?","JPN":"このままじゃリオン死ぬんだぞ！？　マジでリオン死ぬからなああ！？","ENG":"At this rate Liona's gonna die! She's really gonna dieee...!","TWN":"這樣下去萊恩會死的！？真的會死啊啊啊啊啊啊……！？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"큭, 가소롭군……!","JPN":"ちっ、くだらない……！","ENG":"Kgh, how ridiculous...!","TWN":"嘖，真可笑……！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"너 따위가 감히 날 상대할 셈인가?","JPN":"貴様ごときが俺の相手をしようというのか？","ENG":"You think you're worthy of facing me?","TWN":"就憑你，也敢與我為敵嗎？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그래, 네 상대는 나야! 그러니까 녀석을 풀어줘!","JPN":"ああ、お前の相手は俺だ！　だからそいつを放せ！","ENG":"Yeah, your opponent is me! So let him go!","TWN":"沒錯，你的對手是我！所以放了那傢伙！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"저 파편 녀석은 몰라도, 리오나를 일방적으로 죽게 내버려 둘 수는 없어……!","JPN":"あの破片のやつはともかく、リオナを死なせるわけにはいかないんだ……！","ENG":"I don't care about that Fragment, but I won't let Liona die like this...!","TWN":"就算不管那個碎片，我也不能眼睜睜看著萊歐娜被殺……！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그러기 위해서, 이 방패를 짊어진 거니까!","JPN":"そのために俺はこの盾を引き継いだんだ！","ENG":"That's why I carry this shield!","TWN":"正因為如此，我才背負著這面盾牌！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"괜찮아, 루키?","JPN":"大丈夫か、ルーキー？","ENG":"You okay, rookie?","TWN":"沒事吧，菜鳥？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"으으, 죽는 줄 알았네……!","JPN":"うう、死ぬかと思った……！","ENG":"Ugh... I seriously thought I was dead...!","TWN":"唔唔，我以為我要死了……！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"놈팽이! <color=#ffd34c>특별 관리 대상</color>이라면서! 그럼, 특별 관리를 하란 말이야……!","JPN":"おい、チンピラ！　<color=#ffd34c>特別管理対象</color>なんだろ！　なら特別に管理しろってんだ……！","ENG":"You scumbag! You said I was under <color=#ffd34c>special surveillance</color>! Then do some special surveilling already...!","TWN":"你這混帳！不是說是<color=#ffd34c>特別管理對象</color>嗎！那就給我好好特別管理啊……！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 너! 설마 이 둔탱이 좋아해? 그럼, 가슴이라도 만지게 해줘?","JPN":"それにお前！　まさかこのどんくさいのが好きなのか？　胸でも触らせてやろうか？","ENG":"And you! Do you like this dullard or something? You want me to let you grope her chest?","TWN":"還有你！該不會喜歡這個笨蛋吧？那至少讓我摸摸胸部啊？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"……괜히 구했나, 이거?","JPN":"……助けないほうがよかったか、これ。","ENG":"...I saved you for nothing, didn't I?","TWN":"……我是不是白救你了？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"크윽……!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳……！！"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"오랜만이에요, 버넷.","JPN":"久しぶりですね、バーネット。","ENG":"It's been a while, Burnett.","TWN":"好久不見了，伯內特。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"마침 놀이 상대를 찾고 있었는데, 잘 됐네요.","JPN":"ちょうど遊び相手を探していたところなんです。","ENG":"I was just looking for someone to play with. This works out nicely.","TWN":"我正好在找玩伴呢，真是太好了。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"저랑 같이 놀아주시겠어요?","JPN":"一緒に遊んでくれますか？","ENG":"Care to play with me?","TWN":"要不要陪我一起玩啊？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","text":{"KOREA":"제 기관원에게 손 떼세요, 괴물.","JPN":"私の機関員から手を離しなさい、化け物。","ENG":"Hands off my agent, monster.","TWN":"把手從我的機關成員身上拿開，怪物。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"후후, 설마 질투인가요? 못 본 사이에 귀여워지셨네요, 기관장님?","JPN":"ふふ、まさか嫉妬してるんですか？　しばらく見ない間に可愛くなりましたね、機関長。","ENG":"Hehe, jealous? You've gotten cuter since I last saw you, Chief.","TWN":"呵呵，你該不會在吃醋吧？我們沒有見面的這段時間，你變得挺可愛的嘛，機關長？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};